import{_ as l,o as n,c as i,a2 as s}from"./chunks/framework.BnBoz4Zl.js";const u=JSON.parse('{"title":"第 21 章 项目研判分析","description":"项目研判的核心不是让 AI 给出“值得做”或“不值得做”的结论，而是让证据、假设、缺口和风险更清楚。本章使用完全合成的示例介绍通用方法，不展示真实项目或业务体系。 ::: warning 使用边界 WorkBuddy 可以辅助整理资料和形成问题清单，但不能替代法律、财务、工程、运营等专业意见…","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 21 章 项目研判分析/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 21 章 项目研判分析/index.md","lastUpdated":1784100816000}'),e={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 21 章 项目研判分析/index.md"};function t(r,a,o,p,h,d){return n(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="第-21-章-项目研判分析" tabindex="-1">第 21 章 项目研判分析 <a class="header-anchor" href="#第-21-章-项目研判分析" aria-label="Permalink to &quot;第 21 章 项目研判分析&quot;">​</a></h1><p>项目研判的核心不是让 AI 给出“值得做”或“不值得做”的结论，而是让证据、假设、缺口和风险更清楚。本章使用完全合成的示例介绍通用方法，不展示真实项目或业务体系。</p><div class="warning custom-block"><p class="custom-block-title">使用边界</p><p>WorkBuddy 可以辅助整理资料和形成问题清单，但不能替代法律、财务、工程、运营等专业意见，也不能作出投资、审批或项目决策。</p></div><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>对一批项目资料建立目录和完整性检查表。</li><li>从公开或授权材料中提取关键事实和待核实事项。</li><li>建立风险清单、假设清单和证据矩阵。</li><li>为专业评审准备问题清单和汇报结构。</li></ul><h2 id="任务目标" tabindex="-1">任务目标 <a class="header-anchor" href="#任务目标" aria-label="Permalink to &quot;任务目标&quot;">​</a></h2><p>把“感觉上有问题”转化为可验证的问题，把“材料很多”转化为清楚的证据结构，把结论边界交还给有权限的专业人员。</p><h2 id="输入材料" tabindex="-1">输入材料 <a class="header-anchor" href="#输入材料" aria-label="Permalink to &quot;输入材料&quot;">​</a></h2><ul><li>研判目的、范围、截止时间和使用对象。</li><li>已授权的项目资料或合成样本。</li><li>需要关注的维度和专业边界。</li><li>现有结论、关键假设和缺失材料。</li><li>期望输出格式与审批要求。</li></ul><h2 id="执行步骤" tabindex="-1">执行步骤 <a class="header-anchor" href="#执行步骤" aria-label="Permalink to &quot;执行步骤&quot;">​</a></h2><h3 id="第一步-建立资料目录" tabindex="-1">第一步：建立资料目录 <a class="header-anchor" href="#第一步-建立资料目录" aria-label="Permalink to &quot;第一步：建立资料目录&quot;">​</a></h3><p>按材料类别记录文件名、日期、来源、版本、完整性和可用状态。损坏、重复、缺页和无法解析的文件单独列出。</p><h3 id="第二步-形成事实表" tabindex="-1">第二步：形成事实表 <a class="header-anchor" href="#第二步-形成事实表" aria-label="Permalink to &quot;第二步：形成事实表&quot;">​</a></h3><p>每条事实包含内容、来源、时间、可信状态和关联问题。不要把宣传性描述、第三方观点和内部判断混为一类。</p><h3 id="第三步-建立证据矩阵" tabindex="-1">第三步：建立证据矩阵 <a class="header-anchor" href="#第三步-建立证据矩阵" aria-label="Permalink to &quot;第三步：建立证据矩阵&quot;">​</a></h3><p>围绕研判问题列出支持证据、反向证据、缺失证据和待验证假设。证据不足时，不得强行得出确定结论。</p><h3 id="第四步-组织风险与问题" tabindex="-1">第四步：组织风险与问题 <a class="header-anchor" href="#第四步-组织风险与问题" aria-label="Permalink to &quot;第四步：组织风险与问题&quot;">​</a></h3><p>风险条目至少说明风险描述、触发条件、可能影响、现有依据、待补材料、建议核验人和状态。AI 只负责整理，不给风险“拍板”。</p><h3 id="第五步-生成研判材料" tabindex="-1">第五步：生成研判材料 <a class="header-anchor" href="#第五步-生成研判材料" aria-label="Permalink to &quot;第五步：生成研判材料&quot;">​</a></h3><p>输出一页摘要、资料清单、事实表、问题清单和风险清单。任何建议都应说明依据、假设和适用边界。</p><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>假设需要评估“某闲置办公楼改造项目”的资料完整性，所有名称和数字均为虚构。WorkBuddy 可以发现权属材料版本不明、改造预算缺少依据、时间计划存在冲突，并形成待补材料清单；是否推进项目由专业评审和审批程序决定。</p><h3 id="可复制任务模板" tabindex="-1">可复制任务模板 <a class="header-anchor" href="#可复制任务模板" aria-label="Permalink to &quot;可复制任务模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请辅助整理当前目录中的项目资料，不作投资、审批或专业结论。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>研判目的：{目的}</span></span>
<span class="line"><span>材料范围：{目录或文件名}</span></span>
<span class="line"><span>关注维度：{合规/财务/工程/运营/其他}</span></span>
<span class="line"><span>输出对象：{经办人/评审人员/会议材料}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请执行：</span></span>
<span class="line"><span>1. 建立资料目录并标记版本、来源、完整性和异常；</span></span>
<span class="line"><span>2. 形成事实表，每条事实注明出处；</span></span>
<span class="line"><span>3. 区分事实、第三方观点、假设和建议；</span></span>
<span class="line"><span>4. 建立支持证据、反向证据、缺失证据矩阵；</span></span>
<span class="line"><span>5. 生成风险清单和待核实问题，不自行确定风险等级；</span></span>
<span class="line"><span>6. 输出一页摘要、材料缺口和建议的专业复核分工。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不得补造项目事实，不得把模型判断写成正式结论，不得修改原始材料。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>研判范围、评价口径和资料权限是否明确。</li><li>关键事实是否有可靠来源，版本是否一致。</li><li>专业判断是否由对应专业人员完成。</li><li>风险等级、处置建议和最终结论是否经过授权确认。</li><li>输出材料是否适合目标读者和共享范围。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>资料目录：文件状态和缺口清楚。</li><li>事实与证据矩阵：事实有出处，假设有标记。</li><li>风险清单：描述具体、依据可查、状态可追踪。</li><li>待核实问题：说明需要什么材料、由什么专业复核。</li><li>研判摘要：结论边界清楚，不替代正式决策。</li></ul><h2 id="常见弯路" tabindex="-1">常见弯路 <a class="header-anchor" href="#常见弯路" aria-label="Permalink to &quot;常见弯路&quot;">​</a></h2><ul><li><strong>材料没看全就先写结论</strong>：后续容易围绕结论挑证据。先建目录和事实表。</li><li><strong>只收集支持材料</strong>：忽略反向证据会放大确认偏差。证据矩阵必须包含反证。</li><li><strong>把专业判断交给模型</strong>：模型不知道完整现场和责任边界。明确专业复核人。</li></ul><h2 id="安全边界" tabindex="-1">安全边界 <a class="header-anchor" href="#安全边界" aria-label="Permalink to &quot;安全边界&quot;">​</a></h2><ul><li>不展示真实项目名称、金额、交易结构、权属信息和业务流程。</li><li>不把受限资料上传到未经批准的服务。</li><li>不自动发送报告、修改原始材料或触发业务动作。</li><li>不把本章方法描述为公司已经正式采用的研判流程。</li></ul><h2 id="可复用资产" tabindex="-1">可复用资产 <a class="header-anchor" href="#可复用资产" aria-label="Permalink to &quot;可复用资产&quot;">​</a></h2><ul><li>项目资料目录模板。</li><li>事实表与证据矩阵。</li><li>材料缺口清单。</li><li>风险与问题台账。</li><li>研判摘要检查表。</li></ul>`,34)])])}const b=l(e,[["render",t]]);export{u as __pageData,b as default};
